          _mm256_storeu_pd(&out_re[(k+2)*ovs+os*56], _mm256_permute2f128_pd(lo_ab,lo_cd,0x31));
          _mm256_storeu_pd(&out_re[(k+3)*ovs+os*56], _mm256_permute2f128_pd(hi_ab,hi_cd,0x31));
