        x4_re = LD(&in_re[34*is+k]);
        x4_im = LD(&in_im[34*is+k]);
        x5_re = LD(&in_re[42*is+k]);
        x5_im = LD(&in_im[42*is+k]);
        x6_re = LD(&in_re[50*is+k]);
        x6_im = LD(&in_im[50*is+k]);
        x7_re = LD(&in_re[58*is+k]);
        x7_im = LD(&in_im[58*is+k]);

