              __m256d esr=_mm256_sub_pd(x2_re,x6_re), esi=_mm256_sub_pd(x2_im,x6_im);
              _mm256_store_pd(&bfr[0*4],_mm256_add_pd(epr,err)); _mm256_store_pd(&bfi[0*4],_mm256_add_pd(epi,eri));
